import React from "react";
import { useState } from "react";

function App() {
  const [state, setState] = useState(false);


  function toggleVisibility() {
    setState(!state);
  }

  return (
    <>
    <h1> Password Fields </h1>
      <input type={state ? "text" : "password"} /> <br/><br/>
      <button onClick={() => toggleVisibility()}>
        {state ? "Hide" : "Show"}
      </button>
    </>
  );
}

export default App;
